import { useEffect, useMemo, useState } from 'react'
import './App.css'
import { createInitialState, keyToDirection, move, type GameState } from './game'

const App = () => {
  const [gameState, setGameState] = useState<GameState>(() => createInitialState())

  const statusMessage = useMemo(() => {
    if (gameState.status === 'won') {
      return 'You reached 2048! Keep going or restart for a new run.'
    }

    if (gameState.status === 'over') {
      return 'No moves left. Restart to try again.'
    }

    return 'Use arrow keys or WASD to slide the board.'
  }, [gameState.status])

  useEffect(() => {
    const handleKeyDown = (event: KeyboardEvent) => {
      const direction = keyToDirection(event.key)

      if (!direction) {
        return
      }

      event.preventDefault()
      setGameState((currentState) => move(currentState, direction))
    }

    window.addEventListener('keydown', handleKeyDown)
    return () => window.removeEventListener('keydown', handleKeyDown)
  }, [])

  const restart = () => {
    setGameState(createInitialState())
  }

  return (
    <main className="app-shell">
      <section className="game-card">
        <header className="topbar">
          <div>
            <h1>2048</h1>
            <p className="subtitle">Join the numbers and chase the 2048 tile.</p>
          </div>
          <div className="score-panel" aria-label="Current score">
            <span>Score</span>
            <strong>{gameState.score}</strong>
          </div>
        </header>

        <div className="controls">
          <p className={`status status-${gameState.status}`}>{statusMessage}</p>
          <button type="button" onClick={restart} className="restart-button">
            Restart
          </button>
        </div>

        <section className="board" aria-label="2048 board">
          {gameState.board.flatMap((cell, index) => (
            <div
              key={cell?.id ?? `empty-${index}`}
              className={`tile ${cell ? `tile-${cell.value}` : 'tile-empty'}`}
            >
              {cell?.value ?? ''}
            </div>
          ))}
        </section>

        <footer className="help-text">
          <span>Controls: ↑ ↓ ← → or W A S D</span>
          <span>Merge matching tiles once per move to build larger values.</span>
        </footer>
      </section>
    </main>
  )
}

export default App

